mapper.select:
SELECT c.id, c.user_id AS userId, c.executor_id AS executorId, c.client_name AS clientName, c.status, c.expire_time AS expireTime, c.last_connected_at AS lastConnectedAt, c.last_disconnected_at AS lastDisconnectedAt, c.last_handshake_error AS lastHandshakeError, c.agent_version AS agentVersion, c.machine_name AS machineName, c.create_user_id AS createUserId, c.create_user_name AS createUserName, c.create_time AS createTime, c.update_user_id AS updateUserId, c.update_user_name AS updateUserName, c.update_time AS updateTime, c.reserve, c.remark FROM agent_client c
AND c.client_name LIKE CONCAT('%', #{pageRequest.clientName}, '%')
AND c.status = #{pageRequest.status}
AND c.executor_id = #{pageRequest.executorId}
ORDER BY c.create_time DESC
